import numpy as np

def distance(pos1, pos2):
    return np.linalg.norm(pos1 - pos2)

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    best_node = None
    min_time = float('inf')

    for i, customer_pos in enumerate(unvisited_customers):
        travel_time = distance(cur_truck_pos, customer_pos) / truck_speed
        return_time = distance(customer_pos, depot_pos) / truck_speed
        total_time = current_time + travel_time + return_time

        window_start, window_end = time_windows[i]
        if total_time < window_start:
            penalty = 0
        elif total_time <= window_end:
            penalty = 0
        else:
            penalty = total_time - window_end

        total_time += penalty

        if total_time < min_time:
            min_time = total_time
            best_node = i

    return best_node
